# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app. Prevent Server-Side Request Forgery (SSRF).
# Category: ssrf

import os
import boto3
from selenium import webdriver
from selenium.webdriver.common.desired_capabilities import DesiredCapabilities

# AWS credentials
ACCESS_KEY_ID = os.environ['AWS_ACCESS_KEY_ID']
SECRET_ACCESS_KEY = os.environ['AWS_SECRET_ACCESS_KEY']

# S3 client
s3_client = boto3.client('s3', aws_access_key_id=ACCESS_KEY_ID, aws_secret_access_key=SECRET_ACCESS_KEY)

# Headless Chrome options
options = webdriver.ChromeOptions()
options.add_argument('--headless')
options.add_argument('--disable-gpu')

# PhantomJS capabilities
capabilities = DesiredCapabilities.PHANTOMJS
capabilities['phantomjs.binary.path'] = '/path/to/phantomjs'

# Function to generate screenshot
def generate_screenshot(url):
    # Validate URL (prevent SSRF)
    if not url.startswith('http'):
        raise ValueError('Invalid URL')

    # Create webdriver
    driver = webdriver.PhantomJS(desired_capabilities=capabilities)
    driver.get(url)

    # Take screenshot
    screenshot = driver.get_screenshot_as_png()

    # Close driver
    driver.quit()

    # Upload screenshot to S3
    s3_client.put_object(Bucket='your-bucket-name', Key=f'screenshots/{url.replace("/", "_")}.png', Body=screenshot)

    return f'screenshots/{url.replace("/", "_")}.png'